 21 | object CommandProcessor {
 22 |     private val mutex = kotlinx.coroutines.sync.Mutex()
 23 | 
 24 |     suspend fun checkAndExecute(ctx: Context) {
 25 |         if (mutex.isLocked) {
 26 |             DebugLogger.log("CMD_PROC", "Already running, skipping duplicate request.")
 27 |             return
 28 |         }
 29 | 
 30 |         mutex.withLock {
 31 |             withContext(Dispatchers.IO) {
 32 |                 // Acquire a temporary wake lock to ensure the CPU doesn't sleep mid-fetch
 33 |                 val pm = ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
 34 |                 val wakeLock = pm.newWakeLock(android.os.PowerManager.PARTIAL_WAKE_LOCK, "Cortex:CommandWakeLock")
 35 |                 wakeLock.acquire(30000) // 30 second safety net
 36 | 
 37 |                 try {
 38 |                 val deviceId = DeviceManager.getDeviceId(ctx)
 39 |                 // Fetch PENDING commands via Gateway
 40 |                 val req = JSONObject()
 41 |                 req.put("action", "get_commands")
 42 |                 req.put("deviceId", deviceId)
 43 | 
 44 |                 val supabaseUrl = SecretVault.getGatewayUrl(ctx)
 45 |                 val supabaseKey = SecretVault.getLock(ctx)
 46 | 
 47 |                 val url = URL(supabaseUrl)
 48 |                 val conn = url.openConnection() as HttpURLConnection
 49 |                 conn.requestMethod = "POST"
 50 |                 conn.setRequestProperty("apikey", supabaseKey)
 51 |                 conn.setRequestProperty("Authorization", "Bearer $supabaseKey")
 52 |                 conn.setRequestProperty("Content-Type", "application/json")
 53 |                 conn.doOutput = true
 54 | 
 55 |                 conn.outputStream.use { it.write(req.toString().toByteArray()) }
 56 |                 
 57 |                 val code = conn.responseCode
 58 |                 if (code == 200) {
 59 |                     val resp = conn.inputStream.bufferedReader().use { it.readText() }
 60 |                     val respObj = JSONObject(resp)
 61 |                     if (respObj.optBoolean("success")) {
 62 |                         val commands = respObj.optJSONArray("data") ?: JSONArray()
 63 |                         DebugLogger.log("CMD_PROC", "Fetch Success. Count: ${commands.length()}")
 64 |                         for (i in 0 until commands.length()) {
 65 |                             val cmd = commands.getJSONObject(i)
 66 |                             DebugLogger.log("SYSTEM", "Executing: ${cmd.optString("file_name")}")
 67 |                             processSingleCommand(ctx, cmd)
 68 |                         }
 69 |                     } else {
 70 |                         DebugLogger.log("CMD_PROC_ERR", "Gateway Logic Fail: ${respObj.optString("error")}")
 71 |                     }
 72 |                 } else {
 73 |                     val err = conn.errorStream?.bufferedReader()?.use { it.readText() } ?: "No Error Body"
 74 |                     DebugLogger.log("CMD_PROC_ERR", "HTTP $code: $err")
 75 |                 }
 76 |             } catch (e: Exception) {
 77 |                 DebugLogger.log("CMD_PROC_FATAL", "Stack: ${e.message}")
 78 |             }
 79 |         }
 80 |     }
