5084 |                 const ts = new Date(item.created_at).getTime();
5085 |                 const diff = now - ts;
5086 |                 if (f.time === 'hour' && diff > 3600000) return false;
5087 |                 if (f.time === 'today' && diff > 86400000) return false;
5088 |                 if (f.time === 'week' && diff > 604800000) return false;
5089 |             }
5090 | 
5091 |             // 2. File Filter
5092 |             if (f.files.length > 0) {
5093 |                 let touchedFiles = [];
5094 |                 if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
5095 |                 if (tab === 'patcher') {
5096 |                     // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
5097 |                     touchedFiles = (item.results || []).map(r => r.file);
5098 |                 }
5099 |                 if (tab === 'cicd') {
5100 |                     const match = dbHistory.find(h => h.sha === item.head_commit.id);
5101 |                     touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
5102 |                 }
5103 |                 // Filter out empty paths
5104 |                 touchedFiles = touchedFiles.filter(p => p !== '');
5105 |                 if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
5106 |             }
5107 |             return true;
5108 |         });
