5428 |     // --- GENERIC UI ---
5429 |     function formatBytes(bytes) {
5430 |         if (!bytes) return '0 B';
5431 |         const k = 1024;
5432 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5433 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5434 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5435 |     }
