5437 |     function timeAgo(dateString) {
5438 |         const date = new Date(dateString);
5439 |         const now = new Date();
5440 |         const seconds = Math.floor((now - date) / 1000);
5441 |         if (seconds < 10) return 'just now';
5442 |         if (seconds < 60) return seconds + 's ago';
5443 |         const minutes = Math.floor(seconds / 60);
5444 |         if (minutes < 60) return minutes + 'm ago';
5445 |         const hours = Math.floor(minutes / 60);
5446 |         if (hours < 24) return hours + 'h ago';
5447 |         return date.toLocaleDateString();
5448 |     }
