5682 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5683 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5684 |         
5685 |         const navItems = document.querySelectorAll('.nav-item');
5686 |         switchTab(tabId, navItems[navIndex]);
5687 | 
5688 |         const scrollContainer = document.querySelector('.main-view');
5689 |         let retryCount = 0;
5690 |         const MAX_RETRIES = 5;
5691 | 
5692 |         const attemptNavigation = async () => {
5693 |             const element = document.querySelector(selector);
5694 |             
5695 |             if (element) {
5696 |                 console.log("[DeepJump] Element found. Scrolling...");
5697 |                 
5698 |                 // Wait for any tab transition animations
5699 |                 await new Promise(r => setTimeout(r, 300));
5700 | 
5701 |                 let offsetTop = 0;
5702 |                 let curr = element;
5703 |                 while (curr && curr !== scrollContainer) {
5704 |                     offsetTop += curr.offsetTop;
5705 |                     curr = curr.offsetParent;
5706 |                 }
5707 | 
5708 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5709 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5710 | 
5711 |                 // Visual Highlight
5712 |                 element.style.transition = 'all 0.5s ease';
5713 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5714 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5715 |                 setTimeout(() => {
5716 |                     element.style.backgroundColor = '';
5717 |                     element.style.boxShadow = '';
5718 |                 }, 3000);
5719 |                 
5720 |                 console.groupEnd();
5721 |                 return true;
5722 |             }
5723 | 
5724 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5725 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5726 |                 retryCount++;
5727 |                 showGlobalToast("🔍 Searching deeper...");
5728 |                 
5729 |                 await loadMoreFn(); 
5730 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5731 |                 return attemptNavigation();
5732 |             }
5733 | 
5734 |             console.error("[DeepJump] Failed: Element not found after retries.");
5735 |             showGlobalToast("Entry not found in recent history.", true);
5736 |             console.groupEnd();
