7508 | 
7509 |         const idsToDelete = checkboxes.map(cb => cb.value);
7510 |         
7511 |         // Find the oldest record among the selection to determine rollback target
7512 |         // dbHistory is sorted newest -> oldest
7513 |         let oldestSelectedIndex = -1;
7514 |         checkboxes.forEach(cb => {
7515 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7516 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7517 |         });
7518 | 
7519 |         // The target is the first record older than our selection that isn't also being deleted
7520 |         let rollbackTarget = null;
7521 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7522 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7523 |                 rollbackTarget = dbHistory[i];
7524 |                 break;
7525 |             }
7526 |         }
7527 | 
7528 |         let msg = `Delete ${checkboxes.length} selected records?`;
7529 |         if (rollbackTarget) {
7530 |             msg += `\n\n⚠️ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
7531 |         }
7532 | 
7533 |         if (!confirm(msg)) return;
7534 | 
7535 |         showGlobalToast("Batch Deleting & Rolling back...");
