8475 |     function extractTableNames(sql) {
8476 |         if (!sql) return [];
8477 |         const tables = [];
8478 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8479 |         
8480 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8481 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8482 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8483 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8484 | 
8485 |         let match;
8486 |         while ((match = fromRegex.exec(sql)) !== null) {
8487 |             const name = match[1];
8488 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8489 |                 tables.push(name);
8490 |             }
8491 |         }
8492 |         
8493 |         while ((match = metaRegex.exec(sql)) !== null) {
8494 |             const name = match[1];
8495 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8496 |                 tables.push(name);
8497 |             }
8498 |         }
8499 | 
8500 |         return tables;
8501 |     }
8502 | 
8503 |     function convertToCSV(resultObj) {
8504 |         const data = resultObj.data || [];
8505 |         if (!data.length) return '';
8506 |         
8507 |         const tables = extractTableNames(resultObj.sql);
8508 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8509 | 
8510 |         const headers = Object.keys(data[0]);
8511 |         const rows = data.map(row => 
8512 |             headers.map(header => {
8513 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8514 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8515 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8516 |             }).join(',')
8517 |         );
8518 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8519 |     }
