// Using Native AndroidView for maximum performance on large text buffers
Column(modifier = Modifier.fillMaxSize().background(Color(0xFF1E1E1E))) {
    AndroidView(
        modifier = Modifier.fillMaxSize().weight(1f).padding(16.dp),
        factory = { ctx ->
            EditText(ctx).apply {
                inputType = InputType.TYPE_CLASS_TEXT or 
                            InputType.TYPE_TEXT_FLAG_MULTI_LINE or 
                            InputType.TYPE_TEXT_FLAG_NO_SUGGESTIONS
                gravity = Gravity.TOP
                typeface = Typeface.MONOSPACE
                textSize = 14f
                setTextColor(android.graphics.Color.WHITE)
                background = null // Remove the underline

                // Direct buffer management
                setText(viewModel.editorText)

                // Track changes without updating ViewModel state on every char
                addTextChangedListener(object : android.text.TextWatcher {
                    override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) {}
                    override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {}
                    override fun afterTextChanged(s: android.text.Editable?) {
                        // Update a temporary field so we don't trigger global recomposition
                        viewModel.editorText = s.toString()
                    }
                })
            }
        },
        update = { view ->
            view.isEnabled = !viewModel.isEditLocked
            // Only reset text if the file changed (not on every typing action)
            if (view.text.toString() != viewModel.editorText && viewModel.originalText == viewModel.editorText) {
                view.setText(viewModel.editorText)
            }
        }
    )
}

